//Copyright(c)HashiCorp,Inc.//SPDX-License-Identifier:MPL-2.0packageconnectimport("testing")funcTestValidDeskPhoneNumber(t*testing.T){t.Parallel()validNumbers:=[]string{"+12345678912","+6598765432",}for_,v:=rangevalidNumbers{_,errors:=validDeskPhoneNumber(v,"desk_phone_number")iflen(errors)!=0{t.Fatalf("%qshouldbeavaliddeskphonenumber:%q",v,errors)}}invalidNumbers:=[]string{"1232","invalid",}for_,v:=rangeinvalidNumbers{_,errors:=validDeskPhoneNumber(v,"desk_phone_number")iflen(errors)==0{t.Fatalf("%qshouldbeainvaliddeskphonenumber:%q",v,errors)}}}funcTestValidPhoneNumberPrefix(t*testing.T){t.Parallel()validPrefixes:=[]string{"+12345","+659876","+6598765432","+61","+1",}for_,v:=rangevalidPrefixes{_,errors:=validPhoneNumberPrefix(v,"prefix")iflen(errors)!=0{t.Fatalf("%qshouldbeavalidphonenumberprefix:%q",v,errors)}}invalidPrefixes:=[]string{"1232","98765432","invalid",}for_,v:=rangeinvalidPrefixes{_,errors:=validPhoneNumberPrefix(v,"prefix")iflen(errors)==0{t.Fatalf("%qshouldbeainvalidphonenumberprefix:%q",v,errors)}}}